import './Filter.scss';

import { Divider } from ':components/Divider';
import { Search } from ':components/Search';
import type { JSX } from 'react';
import React from 'react';

export interface FilterProps {
	filterPlaceholder: string;
	filterRef: React.MutableRefObject<HTMLInputElement>;
	changeFilterValue: (value: string) => void;
	filterValue: string;
	dataTestId: string;
}

export const Filter = ({
	filterPlaceholder,
	filterRef,
	changeFilterValue,
	filterValue,
	dataTestId,
}: FilterProps): React.JSX.Element => (
	<div>
		<div className="dsb__select__options__filter">
			<Search
				size="small"
				placeholder={filterPlaceholder}
				fullWidth={true}
				ref={filterRef}
				value={filterValue}
				onSearch={(val): void => {
					changeFilterValue(val.toString());
				}}
				onChange={(event): void => {
					changeFilterValue(event.target.value);
				}}
				dataTestId={dataTestId + '-search'}
			/>
		</div>
		<Divider></Divider>
	</div>
);
